import numpy as np

def erosion(image, structuringElement):
  erodedImage = np.zeros(image.shape)
  for i in range(image.shape[0]):
    for j in range(image.shape[1]):
      if np.all(image[i:i+structuringElement.shape[0], j:j+structuringElement.shape[1]] == structuringElement):
        erodedImage[i, j] = 1
  return erodedImage

