void dilation(int **image, int **structuringElement, int **dilatedImage, int n, int m, int k, int l) {
  for (int i = 0; i < n; i++) {
    for (int j = 0; j < m; j++) {
      for (int x = 0; x < k; x++) {
        for (int y = 0; y < l; y++) {
          if (image[i+x][j+y] == 1 && structuringElement[x][y] == 1) {
            dilatedImage[i][j] = 1;
          }
        }
      }
    }
  }
}

public class GrayscaleErosion {
  public static int[][] erosion(int[][] image, int[][] structuringElement) {
    int[][] erodedImage = new int[image.length][image[0].length];
    for (int i = 0; i < image.length; i++) {
      for (int j = 0; j < image[0].length; j++) {
        int min = Integer.MAX_VALUE;
        for (int x = 0; x < structuringElement.length; x++) {
          for (int y = 0; y < structuringElement[0].length; y++) {
            if (structuringElement[x][y] == 1) {
              min = Math.min(min, image[i+x][j+y]);
            }
          }
        }
        erodedImage[i][j] = min;
      }
    }
    return erodedImage;
  }
}
